func (q *Queries) ListSettlementRecoveryJobsPage(ctx context.Context, arg ListSettlementRecoveryJobsPageParams) ([]ListSettlementRecoveryJobsPageRow, error) {
	rows, err := q.db.Query(ctx, listSettlementRecoveryJobsPage,
		arg.Status,
		arg.UserID,
		arg.FromTime,
		arg.ToTime,
		arg.PageOffset,
		arg.PageLimit,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []ListSettlementRecoveryJobsPageRow
	for rows.Next() {
		var i ListSettlementRecoveryJobsPageRow
		if err := rows.Scan(
			&i.ID,
			&i.UserID,
			&i.RequestRecordID,
			&i.AttemptID,
			&i.ReservationID,
			&i.ResponseProtocol,
			&i.ResponseID,
			&i.ResponseModelID,
			&i.ModelID,
			&i.ProviderID,
			&i.ChannelID,
			&i.UpstreamProtocol,
			&i.UpstreamModel,
			&i.FinishClass,
			&i.UpstreamStatusCode,
			&i.Currency,
			&i.EstimatedAmount,
			&i.AuthorizedAmount,
			&i.Status,
			&i.AttemptCount,
			&i.MaxAttempts,
			&i.NextRunAt,
			&i.LockedBy,
			&i.LockedUntil,
			&i.LastErrorCode,
			&i.LastErrorMessage,
			&i.LastAttemptedAt,
			&i.CompletedAt,
			&i.CreatedAt,
			&i.UpdatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

